args.sparql:
SELECT ?winner WHERE {
  wd:Q1137234 wdt:P527 ?award_category.
  ?award_category rdfs:label ?label.
  FILTER(LCASE(STR(?label)) = "entertainer of the year").
  ?winner wdt:P166 ?award_category.
}

SELECT ?winner WHERE {
  wd:Q1137234 wdt:P527 ?category.
  ?category rdfs:label "Entertainer of the Year"@en.
  ?winner wdt:P166 ?category.
}

SELECT ?label WHERE {
  wd:Q1137234 wdt:P527 ?category.
  ?category rdfs:label ?label.
  FILTER(LANG(?label) = 'en').
  FILTER(REGEX(LCASE(STR(?label)), "entertainer"))
}

SELECT ?category ?label WHERE {
  wd:Q1137234 wdt:P527 ?category.
  ?category rdfs:label ?label.
  FILTER(LANG(?label) = 'en').
  FILTER(REGEX(LCASE(STR(?label)), "entertainer", "i"))
}
